async function handleRequest(event) {
  const request = event.request;
  const url = new URL(request.url);
  const cacheKey = url.searchParams.get('cache_key');
  const ttl = parseInt(url.searchParams.get('ttl'));

  if (cacheKey && ttl > 0) {
    const cacheName = 'my-cache';
    const cache = caches.get(cacheName);

    if (!cache) {
      await caches.open(cacheName);
    }

    const cachedResponse = await cache.match(request);
    if (cachedResponse) {
      return cachedResponse;
    }

    const response = await fetch(request);
    const headers = new Headers(response.headers);
    headers.set('Cache-Control', `max-age=${ttl}`);
    const cachedResponse = new Response(response.body, { headers });

    await cache.put(request, cachedResponse);

    return cachedResponse;
  } else {
    const response = await fetch(request);
    return response;
  }
}

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event));
});